const posts = $input.all().map(r => r.json).filter(p => p.Keyword && p.Status === 'published');
const recentPosts = posts.slice(-10);
const now = new Date();
const weekAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);
const newThisWeek = posts.filter(p => {
  if (!p.Date_Published) return false;
  const d = new Date(p.Date_Published);
  return d >= weekAgo;
});
return [{ json: { posts, recentPosts, newThisWeek, totalPublished: posts.length, newThisWeekCount: newThisWeek.length, checkDate: now.toISOString().split('T')[0] } }];

