const rankingsRaw = $('Search Rankings Agent').first().json.output || '{"rankings":[]}';
const data = $('Check Rankings').first().json;
let rankings = [];
try {
  const match = rankingsRaw.match(/\{[\s\S]*\"rankings\"[\s\S]*\}/);
  if (match) rankings = JSON.parse(match[0]).rankings || [];
} catch(e) {}

const ranked = rankings.filter(r => r.found);
const notRanked = rankings.filter(r => !r.found);

const rankRows = rankings.map(r => `
    <tr style="border-bottom:1px solid #eee;">
      <td style="padding:8px 12px;">${r.keyword}</td>
      <td style="padding:8px 12px;text-align:center;font-weight:bold;color:${r.found ? '#2e7d32' : '#c62828'}">${r.position || 'Not ranked'}</td>
    </tr>`).join('');

const newPostRows = data.newThisWeek.map(p => `
    <tr style="border-bottom:1px solid #eee;">
      <td style="padding:8px 12px;">${p.Keyword}</td>
      <td style="padding:8px 12px;"><a href="https://www.midsouthdumpsterms.com/blog/${p.Slug || ''}">View post</a></td>
      <td style="padding:8px 12px;">${p.Date_Published}</td>
    </tr>`).join('');

const html = `<!DOCTYPE html>
<html>
<head><meta charset="utf-8"><style>body{font-family:Arial,sans-serif;max-width:700px;margin:0 auto;color:#333;}h1{color:#1a5276;}h2{color:#2874a6;border-bottom:2px solid #2874a6;padding-bottom:6px;}table{width:100%;border-collapse:collapse;}th{background:#2874a6;color:white;padding:10px 12px;text-align:left;}.stat-box{display:inline-block;background:#eaf2ff;border-left:4px solid #2874a6;padding:12px 20px;margin:8px;border-radius:4px;}.stat-num{font-size:28px;font-weight:bold;color:#1a5276;}.stat-label{font-size:13px;color:#555;}</style></head>
<body>
<h1>📊 MidSouth SEO Weekly Report</h1>
<p style="color:#777;">Week of ${data.checkDate} | midsouthdumpsterms.com</p>

<div style="margin:20px 0;">
  <div class="stat-box"><div class="stat-num">${data.totalPublished}</div><div class="stat-label">Total Blog Posts Live</div></div>
  <div class="stat-box"><div class="stat-num">${data.newThisWeekCount}</div><div class="stat-label">Published This Week</div></div>
  <div class="stat-box"><div class="stat-num">${ranked.length}/${rankings.length}</div><div class="stat-label">Keywords Ranking</div></div>
</div>

${data.newThisWeekCount > 0 ? `<h2>🆕 New Posts This Week</h2>
<table><tr style="background:#f5f5f5;"><th>Keyword</th><th>URL</th><th>Published</th></tr>${newPostRows}</table>` : '<p style="background:#fff9c4;padding:12px;border-radius:4px;">⚠️ No new posts published this week.</p>'}

<h2>🔍 Keyword Rankings (Recent Posts)</h2>
<table><tr style="background:#f5f5f5;"><th>Keyword</th><th>Google Position</th></tr>${rankRows || '<tr><td colspan=2 style="padding:12px;color:#999;">No ranking data available</td></tr>'}</table>

<br><p style="font-size:12px;color:#999;">This report checks approximately where midsouthdumpsterms.com appears in Google search results for each keyword. New posts typically take 2–4 weeks to rank.<br><br>Generated automatically by MidSouth SEO Automation.</p>
